import React, { useState, useEffect } from 'react';

export default function Navbar({ onLogin, onRegister }) {
  const [scrolled, setScrolled] = useState(false);
  const [user, setUser] = useState(null);
  const [dropdownOpen, setDropdownOpen] = useState(false);

  useEffect(() => {
    const fn = () => setScrolled(window.scrollY > 10);
    window.addEventListener('scroll', fn);
    return () => window.removeEventListener('scroll', fn);
  }, []);

  // Check localStorage for logged in user
  useEffect(() => {
    const stored = localStorage.getItem('seniorly_user');
    if (stored) {
      try { setUser(JSON.parse(stored)); } catch (e) {}
    }
    // Listen for login/logout events
    const handleUserChange = () => {
      const u = localStorage.getItem('seniorly_user');
      setUser(u ? JSON.parse(u) : null);
    };
    window.addEventListener('seniorly_auth', handleUserChange);
    return () => window.removeEventListener('seniorly_auth', handleUserChange);
  }, []);

  const handleLogout = () => {
    localStorage.removeItem('seniorly_token');
    localStorage.removeItem('seniorly_user');
    setUser(null);
    setDropdownOpen(false);
    window.dispatchEvent(new Event('seniorly_auth'));
  };

  const initials = user ? `${user.firstName?.[0] || ''}${user.lastName?.[0] || ''}`.toUpperCase() : '';

  return (
    <nav style={{
      position: 'fixed', top: 0, left: 0, right: 0, zIndex: 100,
      padding: '0 6%',
      background: scrolled ? 'rgba(255,255,255,0.97)' : 'transparent',
      backdropFilter: scrolled ? 'blur(16px)' : 'none',
      borderBottom: scrolled ? '1px solid #e2e4ee' : '1px solid transparent',
      transition: 'all 0.3s ease',
      height: 64,
      display: 'flex', alignItems: 'center', justifyContent: 'space-between',
    }}>

      {/* Logo */}
      <a href="#" style={{ display: 'flex', alignItems: 'center', gap: 8, textDecoration: 'none' }}>
        <div style={{
          width: 32, height: 32, borderRadius: 8, background: '#fff',
          display: 'flex', alignItems: 'center', justifyContent: 'center',
          boxShadow: '0 2px 8px rgba(108,78,228,0.2)',
        }}>
          <span style={{ fontFamily: "'Fraunces', serif", fontWeight: 700, fontSize: 15, color: '#6C4EE4', fontStyle: 'italic' }}>S</span>
        </div>
        <span style={{
          fontFamily: "'Fraunces', serif", fontWeight: 700, fontSize: '1.1rem',
          color: scrolled ? '#1a1a2e' : '#fff', letterSpacing: '-0.3px', transition: 'color 0.3s',
        }}>Seniorly</span>
      </a>

      {/* Right side */}
      <div style={{ display: 'flex', gap: 10, alignItems: 'center' }}>
        {user ? (
          // ── Logged in state ──────────────────────────────────────────
          <div style={{ position: 'relative' }}>
            <button
              onClick={() => setDropdownOpen(!dropdownOpen)}
              style={{
                display: 'flex', alignItems: 'center', gap: 8,
                padding: '0.4rem 0.75rem', borderRadius: 50,
                background: scrolled ? '#f0edff' : 'rgba(255,255,255,0.15)',
                border: scrolled ? '1px solid #d4c9ff' : '1px solid rgba(255,255,255,0.4)',
                cursor: 'pointer', transition: 'all 0.2s',
              }}>
              {/* Avatar circle */}
              <div style={{
                width: 28, height: 28, borderRadius: '50%',
                background: '#6C4EE4', color: '#fff',
                display: 'flex', alignItems: 'center', justifyContent: 'center',
                fontSize: '0.72rem', fontWeight: 700, flexShrink: 0,
              }}>
                {initials}
              </div>
              <span style={{
                fontSize: '0.85rem', fontWeight: 500,
                color: scrolled ? '#1a1a2e' : '#fff',
                maxWidth: 100, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap',
              }}>
                {user.firstName}
              </span>
              <span style={{ fontSize: '0.6rem', color: scrolled ? '#888' : 'rgba(255,255,255,0.7)' }}>▼</span>
            </button>

            {/* Dropdown */}
            {dropdownOpen && (
              <div style={{
                position: 'absolute', top: '110%', right: 0,
                background: '#fff', border: '1px solid #e2e4ee',
                borderRadius: 14, padding: '0.5rem',
                minWidth: 200, boxShadow: '0 8px 32px rgba(0,0,0,0.12)',
                zIndex: 200,
              }}>
                {/* User info */}
                <div style={{ padding: '0.75rem 1rem', borderBottom: '1px solid #f0f0f5', marginBottom: '0.4rem' }}>
                  <div style={{ fontFamily: "'Fraunces',serif", fontWeight: 700, fontSize: '0.95rem', color: '#1a1a2e' }}>
                    {user.firstName} {user.lastName}
                  </div>
                  <div style={{ fontSize: '0.75rem', color: '#888899', marginTop: 2 }}>{user.email}</div>
                  <div style={{
                    display: 'inline-block', marginTop: 6,
                    background: '#f0edff', color: '#6C4EE4',
                    fontSize: '0.65rem', fontWeight: 600,
                    padding: '2px 8px', borderRadius: 50,
                    textTransform: 'uppercase', letterSpacing: '0.05em',
                  }}>{user.role}</div>
                </div>

                {/* Menu items */}
                {[
                  { icon: '👤', label: 'My Profile' },
                  { icon: '📚', label: 'My Webinars' },
                  { icon: '🔔', label: 'Notifications' },
                ].map((item, i) => (
                  <button key={i} style={{
                    width: '100%', textAlign: 'left',
                    padding: '0.6rem 1rem', borderRadius: 8,
                    background: 'transparent', border: 'none',
                    fontSize: '0.85rem', color: '#444466',
                    cursor: 'pointer', display: 'flex', alignItems: 'center', gap: 8,
                    transition: 'background 0.15s',
                  }}
                  onMouseEnter={e => e.currentTarget.style.background = '#f4f6fb'}
                  onMouseLeave={e => e.currentTarget.style.background = 'transparent'}>
                    <span>{item.icon}</span> {item.label}
                  </button>
                ))}

                <div style={{ borderTop: '1px solid #f0f0f5', marginTop: '0.4rem', paddingTop: '0.4rem' }}>
                  <button onClick={handleLogout} style={{
                    width: '100%', textAlign: 'left',
                    padding: '0.6rem 1rem', borderRadius: 8,
                    background: 'transparent', border: 'none',
                    fontSize: '0.85rem', color: '#e53e3e',
                    cursor: 'pointer', display: 'flex', alignItems: 'center', gap: 8,
                    transition: 'background 0.15s',
                  }}
                  onMouseEnter={e => e.currentTarget.style.background = '#fff5f5'}
                  onMouseLeave={e => e.currentTarget.style.background = 'transparent'}>
                    <span>🚪</span> Log out
                  </button>
                </div>
              </div>
            )}
          </div>
        ) : (
          // ── Logged out state ─────────────────────────────────────────
          <>
            <button onClick={onLogin} style={{
              padding: '0.48rem 1.2rem', borderRadius: 50,
              border: `1px solid ${scrolled ? '#d0d0e0' : 'rgba(255,255,255,0.5)'}`,
              color: scrolled ? '#444466' : '#fff', background: 'transparent',
              fontSize: '0.85rem', fontWeight: 500, transition: 'all 0.2s', cursor: 'pointer',
            }}>Log in</button>
            <button onClick={onRegister} style={{
              padding: '0.48rem 1.2rem', borderRadius: 50,
              background: '#fff', color: '#6C4EE4',
              fontSize: '0.85rem', fontWeight: 600, transition: 'all 0.2s', cursor: 'pointer',
              boxShadow: '0 2px 10px rgba(108,78,228,0.2)',
            }}>Get Started</button>
          </>
        )}
      </div>
    </nav>
  );
}
